class GRPCInterceptor(grpc.UnaryUnaryClientInterceptor):
    def __init__(self, metadata_callback=None):
        self.metadata_callback = metadata_callback
        
    def intercept_unary_unary(self, continuation, client_call_details, request):
        if self.metadata_callback:
            additional_metadata = self.metadata_callback()
            if additional_metadata:
                if client_call_details.metadata is None:
                    metadata = list(additional_metadata)
                else:
                    metadata = list(client_call_details.metadata) + list(additional_metadata)
                    
                client_call_details = grpc.aio._interceptor._ClientCallDetails(
                    client_call_details.method,
                    client_call_details.timeout,
                    metadata,
                    client_call_details.credentials,
                    client_call_details.wait_for_ready,
                    client_call_details.compression
                )
                
        return continuation(client_call_details, request)


